function register_new_ability() {
		if ( ! current_user_can( 'manage_options' ) ) {
			wp_die(
				__( 'You do not have sufficient permissions to access this page.' ),
				__( 'Error' ),
				array( 'response' => 403 )
			);
		}

		$nonce = LP_Request::get_param( 'nonce' );
		if ( ! wp_verify_nonce( $nonce, 'lp-settings' ) ) {
			wp_die(
				__( 'Nonce is invalid!' ),
				__( 'Error' ),
				array( 'response' => 403 )
			);
		}

		$name = LP_Request::get_param( 'name' );
		if ( empty( $name ) ) {
			$return = array( 'success' => false, 'message' => __( 'Name is required.' ) );
			echo wp_json_encode( $return );
			die;
		}

		$old_name = LP_Request::get_param( 'old_name' );
		if ( ! empty( $old_name ) ) {
			$old_name = sanitize_title( $old_name );
		}

		$name = sanitize_title( $name );

		if ( $old_name && $old_name !== $name ) {
			$old_ability = LP_Course_Post_Type::get_ability_by_slug( $old_name );
			if ( $old_ability ) {
				$return = array( 'success' => false, 'message' => __( 'This ability is already exists.' ) );
				echo wp_json_encode( $return );
				die;
			}
		}

		$ability_id = LP_Course_Post_Type::update_or_insert_ability(
			array(
				'name' => $name,
			)
		);

		$return = array(
			'success' => true,
			'message' => __( 'Ability has been saved.' ),
			'id'    => $ability_id,
		);
		echo wp_json_encode( $return );
		die;
	}

function set_transient( $name, $value, $expiration = 0 ) {
		if ( ! is_string( $name ) ) {
			_deprecated_argument( __FUNCTION__, '3.6.0', __( 'Only string names are allowed.' ) );
			return false;
		}

		$name = strtolower( $name );

		if ( $expiration && ! is_numeric( $expiration ) ) {
			_deprecated_argument( __FUNCTION__, '3.6.0', __( 'Expiration must be numeric.' ) );
			return false;
		}

		$expiration = (int) $expiration;

		$transient = new Transient( $name, $value, $expiration );
		$transient->save();

		return true;
	}

