function allows(string $action, $subject = null, array $context = []): bool
    {
        if (null === $subject) {
            return true;
        }

        if (!$subject instanceof $this->resourceClass) {
            return false;
        }

        $user = $context['user'] ?? null;

        if (null === $user || !$user instanceof UserInterface) {
            return false;
        }

        if (null === $this->permissionFactory) {
            return true;
        }

        $permission = $this->permissionFactory->create($user);

        try {
            return $permission->allows($action, $subject);
        } catch (InvalidArgumentException $e) {
            return false;
        }
    }

