function useDispatch( storeKey ) {
		const { subscribe, dispatch } = useSelect( ( select ) => {
			const { getStore } = select( STORE_NAME );
			const store = getStore( storeKey );
			return {
				subscribe: store.subscribe,
				dispatch: store.dispatch,
			};
		}, [] );
		useEffect( () => {
			subscribe();
		}, [ subscribe ] );
		return dispatch;
	}

