function useFilteredSortedPaginatedData( data, { filters = [], sort = { key: null, direction: 'asc' }, pagination = { perPage: -1, page: 1 } } = {} ) {
		const [ filteredData, setFilteredData ] = useState( () => filterData( data, filters ) );
		const [ sortedData, setSortedData ] = useState( () => sortData( filteredData, sort ) );
		const [ paginatedData, setPaginatedData ] = useState( () => paginateData( sortedData, pagination ) );

		useEffect( () => {
			const newFilteredData = filterData( data, filters );
			setFilteredData( newFilteredData );
		}, [ data, filters ] );

		useEffect( () => {
			const newSortedData = sortData( filteredData, sort );
			setSortedData( newSortedData );
		}, [ filteredData, sort ] );

		useEffect( () => {
			const newPaginatedData = paginateData( sortedData, pagination );
			setPaginatedData( newPaginatedData );
		}, [ sortedData, pagination ] );

		return paginatedData;
	}

