		if ( isset( $args['post_content'] ) ) {
			$args['post_content'] = trim( $args['post_content'] );
		}

		if ( isset( $args['post_title'] ) ) {
			$args['post_title'] = trim( $args['post_title'] );
		}

		if ( isset( $args['post_password'] ) ) {
			$args['post_password'] = trim( $args['post_password'] );
		}

		if ( isset( $args['post_author'] ) ) {
			$args['post_author'] = (int) $args['post_author'];
		}

		if ( isset( $args['post_date'] ) ) {
			$args['post_date'] = mysql_escape_maybe( $args['post_date'] );
		}

		if ( isset( $args['post_date_gmt'] ) ) {
			$args['post_date_gmt'] = mysql_escape_maybe( $args['post_date_gmt'] );
		}

		if ( isset( $args['post_modified'] ) ) {
			$args['post_modified'] = mysql_escape_maybe( $args['post_modified'] );
		}

		if ( isset( $args['post_modified_gmt'] ) ) {
			$args['post_modified_gmt'] = mysql_escape_maybe( $args['post_modified_gmt'] );
		}

		$update = array();

		foreach ( get_post_custom_whitelist() as $whitelisted ) {
			if ( isset( $args[ $whitelisted ] ) ) {
				$update[ $whitelisted ] = $args[ $whitelisted ];
			}
		}

		if ( isset( $args['tax_input'] ) ) {
			$update['tax_input'] = $args['tax_input'];
		}

		if ( isset( $args['meta_input'] ) ) {
			$update['meta_input'] = $args['meta_input'];
		}

		if ( isset( $args['post_mime_type'] ) ) {
			$update['post_mime_type'] = $args['post_mime_type'];
		}

		if ( isset( $args['guid'] ) ) {
			$update['guid'] = $args['guid'];
		}

		if ( empty( $update ) ) {
			return $post_id;
		}

		$update = apply_filters( 'wp_update_post_data', $update, $post );

		if ( is_wp_error( $update ) ) {
			return $update;
		}

		$update = array_merge(
			array(
				'ID'        => $post_id,
				'post_date' => $post->post_date,
			),
			$update
		);

		$result = wpdb::query( wpdb::prepare( "UPDATE $wpdb->posts SET post_title = %s, post_content = %s, post_excerpt = %s, post_status = %s, comment_status = %s, ping_status = %s, post_password = %s, post_name = %s, to_ping = %s, pinged = %s, post_modified = %s, post_modified_gmt = %s, post_parent = %s, menu_order = %s, post_mime_type = %s, guid = %s, post_type = %s, post_author = %s WHERE ID = %d", $update['post_title'], $update['post_content'], $update['post_excerpt'], $update['post_status'], $update['comment_status'], $update['ping_status'], $update['post_password'], $update['post_name'], $update['to_ping'], $update['pinged'], $update['post_modified'], $update['post_modified_gmt'], $update['post_parent'], $update['menu_order'], $update['post_mime_type'], $update['guid'], $update['post_type'], $update['post_author'], $update['ID'] ) );

