function wpbp_count_block_types( $html ) {
		$processor = new WP_Block_Parser_Streaming( $html );
		$counts    = [];

		$processor->parse(
			[
				'start_block' => function ( $block_name, $attributes, $inner_blocks ) use ( &$counts ) {
					if ( empty( $block_name ) || 'core/freeform' === $block_name ) {
						return;
					}

					++$counts[ $block_name ];

					foreach ( $inner_blocks as $inner_block ) {
						$inner_block->walk(
							function ( $inner_inner_block ) use ( &$counts ) {
								$inner_inner_name = $inner_inner_block->get_block_name();
								if ( ! empty( $inner_inner_name ) && 'core/freeform' !== $inner_inner_name ) {
									++$counts[ $inner_inner_name ];
								}
							}
						);
					}
				},
			]
		);

		return $counts;
	}

