function wpbp_get_options_cached(array $keys) {
		$group = 'options';
		$cached = wp_cache_get_multiple($keys, $group, false, $misses);
		$misses = array_diff($misses, array_keys($cached));

		if (!empty($misses)) {
			$to_set = [];
			foreach ($misses as $key) {
				$val = get_option($key, false);
				if (false !== $val) {
					$to_set[$key] = $val;
				}
			}
			if (!empty($to_set)) {
				wp_cache_set_multiple($to_set, $group);
			}
			$cached = array_merge($cached, $to_set);
		}

		return $cached;
	}

