function register_get_movies_ability() {
	acf_register_ability(
		'demo/get-movies',
		array(
			'input'   => array(
				'properties' => array(
					'genre' => array(
						'type'        => 'string',
						'description' => 'Filter movies by genre.',
					),
				),
				'additionalProperties' => false,
			),
			'output'  => array(
				'type' => 'array',
				'items' => array(
					'type' => 'string',
				),
			),
			'handler' => function ( $input ) {
				$cache_key = 'demo_get_movies_' . ( $input['genre'] ?? '' );
				$salt      = wp_cache_get_last_changed( 'post-queries' );

				$cached = wp_cache_get_salted( $cache_key, 'post-queries', $salt );
				if ( false !== $cached ) {
					return $cached;
				}

				$args = array(
					'post_type'   => 'movie',
					'post_status' => 'publish',
					'fields'      => 'ids',
				);
				if ( ! empty( $input['genre'] ) ) {
					$args['tax_query'] = array(
						array(
							'taxonomy' => 'movie_genre',
							'field'    => 'slug',
							'terms'    => $input['genre'],
						),
					);
				}

				$query   = new WP_Query( $args );
				$post_id = $query->posts[0] ?? 0;
				$title   = get_the_title( $post_id );

				$return = array();
				for ( $i = 0; $i < 10; $i++ ) {
					$return[] = $title . ' ' . $i;
				}

				wp_cache_set_salted( $return, $cache_key, 'post-queries', $salt );

				return $return;
			},
			'meta'    => array(
				'show_in_rest' => true,
			),
			'permission_callback' => function () {
				return current_user_can( 'read' );
			},
		)
	);
}
add_action( 'wp_abilities_api_init', 'register_get_movies_ability' );

