function wpbp_strip_scripts($html) {
		$processor = new WP_HTML_Tag_Processor($html);
		$found_script = false;

		while ($processor->next_tag('script')) {
			$found_script = true;
			$processor->remove_tag();
		}

		if (!$found_script) {
			return $html;
		}

		return $processor->get_result();
	}

