function wpbp_replace_script_text( $html, $replacement ) {
		if ( false !== strpos( $replacement, '<script' ) || false !== strpos( $replacement, '</script' ) ) {
			return false;
		}

		$processor = new WP_HTML_Tag_Processor( $html );
		$found     = $processor->next_tag( 'script' );

		if ( ! $found ) {
			return $html;
		}

		$processor->set_modifiable_text( $replacement );

		if ( ! $processor->get_updated_html() ) {
			return false;
		}

		return $processor->get_updated_html();
	}

