function wpbp_router_link( $url, $text ) {
		$url   = esc_url( $url );
		$text  = esc_html( $text );
		$parts = wp_parse_url( $url );

		if ( ! $parts ) {
			return '';
		}

		$same_site = (
			( ! empty( $parts['scheme'] ) && ! empty( $GLOBALS['wp']->request ) ) &&
			( $parts['scheme'] === wp_parse_url( get_home_url(), PHP_URL_SCHEME ) ) &&
			( $parts['host'] === wp_parse_url( get_home_url(), PHP_URL_HOST ) )
		);

		$html = sprintf(
			'<a href="%s" data-wp-router-replace="true" data-wp-router-prefetch="intent" %s>',
			$url,
			! $same_site ? 'rel="nofollow"' : ''
		);
		$html .= $text;
		$html .= '</a>';

		return $html;
	}

