function get_recent_news_posts() {
		$args = array(
			'post_type'              => 'post',
			'post_status'            => 'publish',
			'category_name'          => 'news',
			'posts_per_page'         => 5,
			'orderby'                => 'date',
			'order'                  => 'DESC',
		);

		$query = new WP_Query( $args );

		if ( ! $query->have_posts() ) {
			return array();
		}

		$posts = array();

		while ( $query->have_posts() ) {
			$query->the_post();
			$posts[] = (object) get_post();
		}

		wp_reset_postdata();

		return $posts;
	}

