function demo_register_books_route() {
	register_rest_route( 'demo/v1', '/books', array(
		'methods'             => WP_REST_Server::READABLE,
		'callback'            => 'demo_get_books',
		'permission_callback' => '__return_true',
	) );
}
add_action( 'rest_api_init', 'demo_register_books_route' );

function demo_get_books() {
	$last_changed = wp_cache_get_last_changed( 'posts' );
	$cache_key    = wp_cache_salted_key( 'books-list', $last_changed );

	$cached = wp_cache_get_salted( $cache_key, 'books-list', false, $found );
	if ( $found ) {
		return $cached;
	}

	$query = new WP_Query( array(
		'post_type'   => 'book',
		'post_status' => 'publish',
		'fields'      => 'ids',
		'no_found_rows' => true,
	) );

	$titles = array();
	foreach ( $query->posts as $id ) {
		$titles[] = get_the_title( $id );
	}

	wp_cache_set_salted( $cache_key, $titles, 'books-list', 30 * MINUTE_IN_SECONDS );

	return $titles;
}

function demo_invalidate_books_cache( $post_id ) {
	if ( 'book' === get_post_type( $post_id ) ) {
		wp_cache_delete_salted( wp_cache_salted_key( 'books-list', wp_cache_get_last_changed( 'posts' ) ), 'books-list' );
	}
}
add_action( 'save_post_book', 'demo_invalidate_books_cache' );
add_action( 'deleted_post', 'demo_invalidate_books_cache' );

